namespace sv_fc44737ab4344333860a894e19743861.Client.Models;

public class Shipment
{
    public string TrackingNumber { get; set; } = string.Empty;
    public string Status { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public DateTime? EstimatedDelivery { get; set; }
    public List<StatusUpdate> StatusUpdates { get; set; } = new();
}

public class StatusUpdate
{
    public string Description { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
    public string Location { get; set; } = string.Empty;
}

using sv_fc44737ab4344333860a894e19743861.Client.Models;

namespace sv_fc44737ab4344333860a894e19743861.Client.Services;

public interface IShipmentService
{
    Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_fc44737ab4344333860a894e19743861.Client.Models;
using sv_fc44737ab4344333860a894e19743861.Client.Services;

namespace sv_fc44737ab4344333860a894e19743861.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new()
    {
        ["PKG-001"] = new Shipment
        {
            TrackingNumber = "PKG-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = DateTime.Today.AddDays(2),
            StatusUpdates = new List<StatusUpdate>
            {
                new() { Description = "Package picked up", Timestamp = DateTime.Today.AddDays(-3), Location = "New York, NY" },
                new() { Description = "Departed facility", Timestamp = DateTime.Today.AddDays(-2), Location = "New York, NY" },
                new() { Description = "Arrived at sorting center", Timestamp = DateTime.Today.AddDays(-1), Location = "Chicago, IL" },
            }
        },
        ["PKG-002"] = new Shipment
        {
            TrackingNumber = "PKG-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = DateTime.Today.AddDays(-1),
            StatusUpdates = new List<StatusUpdate>
            {
                new() { Description = "Package picked up", Timestamp = DateTime.Today.AddDays(-5), Location = "Seattle, WA" },
                new() { Description = "In transit", Timestamp = DateTime.Today.AddDays(-4), Location = "Portland, OR" },
                new() { Description = "Out for delivery", Timestamp = DateTime.Today.AddDays(-1), Location = "San Francisco, CA" },
                new() { Description = "Delivered", Timestamp = DateTime.Today.AddDays(-1).AddHours(14), Location = "San Francisco, CA" },
            }
        },
        ["PKG-003"] = new Shipment
        {
            TrackingNumber = "PKG-003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = DateTime.Today.AddDays(5),
            StatusUpdates = new List<StatusUpdate>
            {
                new() { Description = "Label created", Timestamp = DateTime.Today, Location = "Dallas, TX" },
            }
        }
    };

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
    }
}

using System.Net;
using System.Net.Http.Json;
using sv_fc44737ab4344333860a894e19743861.Client.Models;

namespace sv_fc44737ab4344333860a894e19743861.Client.Services;

public class ShipmentServiceClient : IShipmentService
{
    private readonly HttpClient _http;

    public ShipmentServiceClient(HttpClient http)
    {
        _http = http;
    }

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await _http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == HttpStatusCode.NotFound)
        {
            throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
        }

        response.EnsureSuccessStatusCode();

        return await response.Content.ReadFromJsonAsync<Shipment>(ct)
            ?? throw new InvalidOperationException("Received empty response from server.");
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_fc44737ab4344333860a894e19743861.Client.Models
@using sv_fc44737ab4344333860a894e19743861.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<Shipment> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

<h2>Shipment Tracking</h2>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger">
        <p>@_errorMessage</p>
        <button class="btn btn-primary" @onclick="LoadShipment">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <div class="shipment-details">
        <dl>
            <dt>Tracking Number</dt>
            <dd>@_shipment.TrackingNumber</dd>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Current Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@(_shipment.EstimatedDelivery?.ToString("D") ?? "N/A")</dd>
        </dl>

        <h3>Status Updates</h3>
        @if (_shipment.StatusUpdates.Count > 0)
        {
            <table class="table">
                <thead>
                    <tr>
                        <th>Date</th>
                        <th>Location</th>
                        <th>Description</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var update in _shipment.StatusUpdates.OrderByDescending(u => u.Timestamp))
                    {
                        <tr>
                            <td>@update.Timestamp.ToString("g")</td>
                            <td>@update.Location</td>
                            <td>@update.Description</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p>No status updates available.</p>
        }
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private Client.Models.Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipment();
    }

    private async Task LoadShipment()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed; do nothing
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || !ct.IsCancellationRequested)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (KeyNotFoundException ex)
        {
            Logger.LogWarning(ex, "Shipment not found: {TrackingNumber}", TrackingNumber);
            _errorMessage = $"Shipment '{TrackingNumber}' was not found.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

