using System.Net;
using System.Net.Http.Json;
using sv_fc44737ab4344333860a894e19743861.Client.Models;

namespace sv_fc44737ab4344333860a894e19743861.Client.Services;

public class ShipmentServiceClient : IShipmentService
{
    private readonly HttpClient _http;

    public ShipmentServiceClient(HttpClient http)
    {
        _http = http;
    }

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await _http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == HttpStatusCode.NotFound)
        {
            throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
        }

        response.EnsureSuccessStatusCode();

        return await response.Content.ReadFromJsonAsync<Shipment>(ct)
            ?? throw new InvalidOperationException("Received empty response from server.");
    }
}

